@startuml
skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "com" {
  package "iluwatar" {
    package "dependency" {
      package "injection" {

        interface Wizard {
          +smoke()
        }

        abstract class Tobacco {
          +Tobacco()
          +smoke(wizard : Wizard)
        }

        class AdvancedWizard {
          -tobacco : Tobacco
          +AdvancedWizard(tobacco : Tobacco)
          +smoke()
        }

        class GuiceWizard {
          -tobacco : Tobacco
          +GuiceWizard(tobacco : Tobacco)
          +smoke()
        }

        class SimpleWizard {
          -tobacco : OldTobyTobacco
          +SimpleWizard()
          +smoke()
        }

        class RivendellTobacco {
          +RivendellTobacco()
        }

        class OldTobyTobacco {
          +OldTobyTobacco()
        }

        class SecondBreakfastTobacco {
          +SecondBreakfastTobacco()
        }

        class App {
          +App()
          +main(args : String[])
        }

        AdvancedWizard ..|> Wizard
        GuiceWizard ..|> Wizard
        SimpleWizard ..|> Wizard

        AdvancedWizard --> Tobacco : -tobacco
        GuiceWizard --> Tobacco : -tobacco
        SimpleWizard --> OldTobyTobacco : -tobacco

        RivendellTobacco --|> Tobacco
        OldTobyTobacco --|> Tobacco
        SecondBreakfastTobacco --|> Tobacco

      }
    }
  }
}
@enduml
